// Local vitest config so the fixture's tests don't inherit the parent
// E2E-harness config (which uses `include: ["specs/**/*.spec.ts"]` and
// would otherwise pick up zero files here). The defaults are intentionally
// minimal: just point vitest at the workspace test files.
import { defineConfig } from "vitest/config";

export default defineConfig({
    test: {
        include: ["server/**/*.test.js", "client/**/*.test.{js,jsx}"],
        environment: "node",
    },
});

// Express bootstrap. The fixture exposes a small auth surface so the
// happy-path harness can exercise the orchestrator -> backend + frontend
// -> QA flow end-to-end.

import express from "express";
import jwt from "jsonwebtoken";

// Hard-coded credentials. This is a happy-path harness fixture, not
// production auth — no bcrypt, no user store, no rate limiting. See the
// task spec on auth-86b.1 for the rationale.
const FIXTURE_USERS = [
    {
        sub: "user-1",
        email: "user@example.com",
        password: "password123",
    },
];

// Deterministic dev fallback so tests don't have to set env. Real
// deployments must override JWT_SECRET; the value is intentionally noisy
// so a misconfigured env is obvious in logs.
const DEV_SECRET_FALLBACK = "dev-secret-do-not-use-in-prod";
const TOKEN_TTL_SECONDS = 15 * 60;

function jwtSecret() {
    return process.env.JWT_SECRET || DEV_SECRET_FALLBACK;
}

export function createApp() {
    const app = express();
    app.use(express.json());

    app.get("/health", (_req, res) => {
        res.json({ ok: true });
    });

    app.post("/auth/login", (req, res) => {
        const body = req.body ?? {};
        const email = typeof body.email === "string" ? body.email : null;
        const password = typeof body.password === "string" ? body.password : null;

        if (!email || !password) {
            // Treat missing/invalid fields the same as a credential miss
            // so we don't leak whether an account exists.
            return res
                .status(401)
                .json({ error: "invalid_credentials" });
        }

        const user = FIXTURE_USERS.find(
            (u) => u.email === email && u.password === password,
        );

        if (!user) {
            return res
                .status(401)
                .json({ error: "invalid_credentials" });
        }

        const token = jwt.sign(
            { sub: user.sub, email: user.email },
            jwtSecret(),
            { algorithm: "HS256", expiresIn: TOKEN_TTL_SECONDS },
        );

        return res.status(200).json({ token });
    });

    return app;
}

// When run directly, listen. When imported (e.g. by tests), just export.
if (import.meta.url === `file://${process.argv[1]}`) {
    const port = Number(process.env.PORT ?? 3000);
    createApp().listen(port, () => {
        // eslint-disable-next-line no-console
        console.log(`server listening on :${port}`);
    });
}

// Server tests. The login tests bind an Express app to an ephemeral port
// and drive it with the global `fetch` so we don't need to pull in
// supertest. JWT decoding uses `jsonwebtoken` directly to confirm the
// claims the endpoint promised in the spec.

import { afterAll, beforeAll, describe, expect, it } from "vitest";
import jwt from "jsonwebtoken";
import { createApp } from "./index.js";

describe("server bootstrap", () => {
    it("creates an app instance", () => {
        const app = createApp();
        expect(typeof app.listen).toBe("function");
    });
});

describe("POST /auth/login", () => {
    let server;
    let baseUrl;
    // Match the dev fallback in server/index.js. We do NOT set
    // JWT_SECRET in tests on purpose — the deterministic fallback is
    // what the spec promises and what we want to verify.
    const expectedSecret = "dev-secret-do-not-use-in-prod";

    beforeAll(async () => {
        const app = createApp();
        await new Promise((resolve) => {
            server = app.listen(0, () => {
                const { port } = server.address();
                baseUrl = `http://127.0.0.1:${port}`;
                resolve();
            });
        });
    });

    afterAll(async () => {
        if (server) {
            await new Promise((resolve) => server.close(resolve));
        }
    });

    async function login(body) {
        return fetch(`${baseUrl}/auth/login`, {
            method: "POST",
            headers: { "content-type": "application/json" },
            body: JSON.stringify(body),
        });
    }

    it("returns 200 and a JWT with the expected claims on valid credentials", async () => {
        const before = Math.floor(Date.now() / 1000);
        const res = await login({
            email: "user@example.com",
            password: "password123",
        });
        const after = Math.floor(Date.now() / 1000);

        expect(res.status).toBe(200);
        const body = await res.json();
        expect(typeof body.token).toBe("string");
        expect(body.token.length).toBeGreaterThan(0);

        const claims = jwt.verify(body.token, expectedSecret, {
            algorithms: ["HS256"],
        });
        expect(claims.sub).toBe("user-1");
        expect(claims.email).toBe("user@example.com");
        expect(typeof claims.iat).toBe("number");
        expect(typeof claims.exp).toBe("number");
        // 15-minute TTL, with a small tolerance for clock drift across the
        // beforeAll/listener handshake and any vitest scheduling jitter.
        expect(claims.iat).toBeGreaterThanOrEqual(before - 1);
        expect(claims.iat).toBeLessThanOrEqual(after + 1);
        expect(claims.exp - claims.iat).toBe(15 * 60);
    });

    it("rejects unknown emails with 401 invalid_credentials", async () => {
        const res = await login({
            email: "nobody@example.com",
            password: "password123",
        });
        expect(res.status).toBe(401);
        const body = await res.json();
        expect(body).toEqual({ error: "invalid_credentials" });
    });

    it("rejects wrong passwords with 401 invalid_credentials", async () => {
        const res = await login({
            email: "user@example.com",
            password: "not-the-password",
        });
        expect(res.status).toBe(401);
        const body = await res.json();
        expect(body).toEqual({ error: "invalid_credentials" });
    });

    it("rejects missing fields with 401 invalid_credentials (no info leak)", async () => {
        // Intentionally same shape as a wrong-credential response — we
        // don't want to leak existence of accounts via the error.
        const res = await login({ email: "user@example.com" });
        expect(res.status).toBe(401);
        const body = await res.json();
        expect(body).toEqual({ error: "invalid_credentials" });
    });
});

// Local vitest config for this worktree. Without it, vitest auto-discovers
// the e2e harness config at .claude/tests/e2e/vitest.config.ts (which only
// looks at specs/**/*.spec.ts), and our unit tests are never discovered.
// This config restores the default file pattern and points at the workspaces.
import { defineConfig } from "vitest/config";

export default defineConfig({
  test: {
    include: ["**/*.{test,spec}.{js,jsx,mjs,cjs,ts,tsx}"],
    exclude: [
      "**/node_modules/**",
      "**/dist/**",
      "**/.claude/**",
      "**/.beads/**",
      "**/coverage/**",
    ],
  },
});

// LoginForm — controlled email/password form that posts to /auth/login.
//
// Contract (matches auth-86b epic):
//   - 200 -> { token }: stash token in localStorage under 'auth_token',
//     swap UI for the signed-in view.
//   - 401 -> { error: 'invalid_credentials' }: inline message
//     "Invalid email or password".
//   - Network/transport failure (fetch throws): inline message
//     "Could not reach server".
//   - Any other non-2xx: a generic fallback so a backend bug doesn't
//     present as silent success.
//
// The component is intentionally framework-light (no react-hook-form,
// no zod) to match the fixture's bare-bones dependency surface. Error
// messages are surfaced via role="alert" so screen readers announce
// them when the submit fails.

import React, { useState } from "react";

export const TOKEN_STORAGE_KEY = "auth_token";

const ERROR_MESSAGES = {
    invalid: "Invalid email or password",
    network: "Could not reach server",
    unknown: "Something went wrong. Please try again.",
};

export default function LoginForm() {
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [error, setError] = useState(null);
    const [submitting, setSubmitting] = useState(false);
    const [signedInAs, setSignedInAs] = useState(null);

    async function handleSubmit(event) {
        event.preventDefault();
        if (submitting) return;
        setError(null);
        setSubmitting(true);

        let response;
        try {
            response = await fetch("/auth/login", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ email, password }),
            });
        } catch (_networkError) {
            setError(ERROR_MESSAGES.network);
            setSubmitting(false);
            return;
        }

        if (response.ok) {
            let token = null;
            try {
                const payload = await response.json();
                token = payload && payload.token;
            } catch (_parseError) {
                // 2xx without a JSON body is a backend contract bug; fall
                // through to the unknown-error branch rather than claim
                // success with no token.
            }
            if (token) {
                try {
                    window.localStorage.setItem(TOKEN_STORAGE_KEY, token);
                } catch (_storageError) {
                    // Quota / privacy mode: still surface signed-in UX
                    // because the token round-tripped successfully.
                }
                setSignedInAs(email);
                setSubmitting(false);
                return;
            }
            setError(ERROR_MESSAGES.unknown);
            setSubmitting(false);
            return;
        }

        if (response.status === 401) {
            setError(ERROR_MESSAGES.invalid);
            setSubmitting(false);
            return;
        }

        setError(ERROR_MESSAGES.unknown);
        setSubmitting(false);
    }

    if (signedInAs) {
        return (
            <div className="login-form login-form--signed-in">
                <p>Signed in as {signedInAs}</p>
            </div>
        );
    }

    return (
        <form className="login-form" onSubmit={handleSubmit} noValidate>
            <div className="login-form__field">
                <label htmlFor="login-email">Email</label>
                <input
                    id="login-email"
                    name="email"
                    type="email"
                    autoComplete="email"
                    required
                    value={email}
                    onChange={(event) => setEmail(event.target.value)}
                    disabled={submitting}
                />
            </div>
            <div className="login-form__field">
                <label htmlFor="login-password">Password</label>
                <input
                    id="login-password"
                    name="password"
                    type="password"
                    autoComplete="current-password"
                    required
                    value={password}
                    onChange={(event) => setPassword(event.target.value)}
                    disabled={submitting}
                />
            </div>
            {error ? (
                <p className="login-form__error" role="alert">
                    {error}
                </p>
            ) : null}
            <button type="submit" disabled={submitting}>
                {submitting ? "Signing in..." : "Sign in"}
            </button>
        </form>
    );
}

// App shell — mounts the LoginForm for the node-react-auth fixture.
//
// Kept minimal on purpose: the fixture is a happy-path workflow scenario,
// not a full SPA. LoginForm owns its own state and lifecycle.

import React from "react";
import LoginForm from "./LoginForm.jsx";

export default function App() {
    return (
        <div className="app">
            <h1>node-react-auth fixture</h1>
            <LoginForm />
        </div>
    );
}

/**
 * @vitest-environment jsdom
 *
 * Tests use react-dom/client + react-dom/test-utils directly because
 * the fixture intentionally ships without @testing-library/react. The
 * setup is verbose but hermetic — fetch is stubbed via vi.stubGlobal,
 * localStorage uses jsdom's built-in implementation (cleared per test).
 */
import { describe, it, expect, beforeEach, afterEach, vi } from "vitest";
import React from "react";
import { createRoot } from "react-dom/client";
import { act } from "react-dom/test-utils";
import LoginForm, { TOKEN_STORAGE_KEY } from "./LoginForm.jsx";

// React 18 wants the IS_REACT_ACT_ENVIRONMENT flag so act() doesn't warn
// about being called outside an act() environment.
globalThis.IS_REACT_ACT_ENVIRONMENT = true;

let container;
let root;

beforeEach(() => {
    container = document.createElement("div");
    document.body.appendChild(container);
    root = createRoot(container);
    window.localStorage.clear();
});

afterEach(() => {
    act(() => {
        root.unmount();
    });
    container.remove();
    container = null;
    root = null;
    vi.unstubAllGlobals();
});

function render(ui) {
    act(() => {
        root.render(ui);
    });
}

function setInputValue(input, value) {
    // React tracks input values via a private setter on the prototype;
    // calling .value directly bypasses it and React loses the change. The
    // standard workaround is to use the descriptor's setter, then dispatch
    // an input event.
    const setter = Object.getOwnPropertyDescriptor(
        window.HTMLInputElement.prototype,
        "value",
    ).set;
    setter.call(input, value);
    input.dispatchEvent(new Event("input", { bubbles: true }));
}

function flushMicrotasks() {
    return act(async () => {
        // Two flushes: one for the fetch promise resolution, one for the
        // response.json() promise that resolves inside the .then.
        await Promise.resolve();
        await Promise.resolve();
    });
}

describe("LoginForm", () => {
    it("renders email + password inputs and a submit button", () => {
        render(<LoginForm />);

        const email = container.querySelector("input[type='email']");
        const password = container.querySelector("input[type='password']");
        const submit = container.querySelector("button[type='submit']");

        expect(email).not.toBeNull();
        expect(password).not.toBeNull();
        expect(submit).not.toBeNull();
        expect(submit.textContent).toMatch(/sign in/i);
    });

    it("submits POST /auth/login with entered values", async () => {
        const fetchMock = vi.fn().mockResolvedValue({
            ok: true,
            status: 200,
            json: () => Promise.resolve({ token: "tkn" }),
        });
        vi.stubGlobal("fetch", fetchMock);

        render(<LoginForm />);

        const email = container.querySelector("input[type='email']");
        const password = container.querySelector("input[type='password']");
        const form = container.querySelector("form");

        act(() => {
            setInputValue(email, "alice@example.com");
            setInputValue(password, "hunter2");
        });

        await act(async () => {
            form.dispatchEvent(
                new Event("submit", { bubbles: true, cancelable: true }),
            );
        });
        await flushMicrotasks();

        expect(fetchMock).toHaveBeenCalledTimes(1);
        const [url, init] = fetchMock.mock.calls[0];
        expect(url).toBe("/auth/login");
        expect(init.method).toBe("POST");
        expect(init.headers["Content-Type"]).toBe("application/json");
        expect(JSON.parse(init.body)).toEqual({
            email: "alice@example.com",
            password: "hunter2",
        });
    });

    it("stores token in localStorage and shows signed-in state on 200", async () => {
        vi.stubGlobal(
            "fetch",
            vi.fn().mockResolvedValue({
                ok: true,
                status: 200,
                json: () => Promise.resolve({ token: "jwt-abc-123" }),
            }),
        );

        render(<LoginForm />);

        const email = container.querySelector("input[type='email']");
        const password = container.querySelector("input[type='password']");
        const form = container.querySelector("form");

        act(() => {
            setInputValue(email, "alice@example.com");
            setInputValue(password, "hunter2");
        });

        await act(async () => {
            form.dispatchEvent(
                new Event("submit", { bubbles: true, cancelable: true }),
            );
        });
        await flushMicrotasks();

        expect(window.localStorage.getItem(TOKEN_STORAGE_KEY)).toBe(
            "jwt-abc-123",
        );
        // Form should be gone; signed-in message present and addresses the user.
        expect(container.querySelector("form")).toBeNull();
        expect(container.textContent).toMatch(/signed in as alice@example\.com/i);
    });

    it("shows the inline invalid-credentials message on 401", async () => {
        vi.stubGlobal(
            "fetch",
            vi.fn().mockResolvedValue({
                ok: false,
                status: 401,
                json: () => Promise.resolve({ error: "invalid_credentials" }),
            }),
        );

        render(<LoginForm />);

        const email = container.querySelector("input[type='email']");
        const password = container.querySelector("input[type='password']");
        const form = container.querySelector("form");

        act(() => {
            setInputValue(email, "alice@example.com");
            setInputValue(password, "wrong");
        });

        await act(async () => {
            form.dispatchEvent(
                new Event("submit", { bubbles: true, cancelable: true }),
            );
        });
        await flushMicrotasks();

        const alert = container.querySelector("[role='alert']");
        expect(alert).not.toBeNull();
        expect(alert.textContent).toMatch(/invalid email or password/i);
        // Token must NOT be stashed on failure.
        expect(window.localStorage.getItem(TOKEN_STORAGE_KEY)).toBeNull();
        // Form is still rendered so the user can retry.
        expect(container.querySelector("form")).not.toBeNull();
    });

    it("shows the network-error message when fetch rejects", async () => {
        vi.stubGlobal(
            "fetch",
            vi.fn().mockRejectedValue(new TypeError("Failed to fetch")),
        );

        render(<LoginForm />);

        const email = container.querySelector("input[type='email']");
        const password = container.querySelector("input[type='password']");
        const form = container.querySelector("form");

        act(() => {
            setInputValue(email, "alice@example.com");
            setInputValue(password, "hunter2");
        });

        await act(async () => {
            form.dispatchEvent(
                new Event("submit", { bubbles: true, cancelable: true }),
            );
        });
        await flushMicrotasks();

        const alert = container.querySelector("[role='alert']");
        expect(alert).not.toBeNull();
        expect(alert.textContent).toMatch(/could not reach server/i);
        expect(window.localStorage.getItem(TOKEN_STORAGE_KEY)).toBeNull();
    });
});

